function DashboardPage({ schedule, onBack, onGoToFriends, onLogout }) {
  const planText = schedule?.plan || "";
  const meta = schedule?.meta;

  return (
    <div className="container-center">
      <div className="card">
        <div className="topbar">
          <div>
            <div className="subtitle">Üretilen çalışma planın</div>
            <h2 className="title" style={{ marginBottom: 0 }}>
              Dashboard
            </h2>
          </div>
          <button className="btn btn-danger" onClick={onLogout}>
            Çıkış Yap
          </button>
        </div>

        <div className="section-title">Plan</div>
        {meta && (
          <div className="muted" style={{ marginBottom: 10 }}>
            {meta.exam} | {meta.hours} saat/gün | {meta.subjectsCount} ders |{" "}
            {meta.topicsCount} topic
            {meta.generator ? ` | ${meta.generator}` : ""}
          </div>
        )}
        {planText ? (
          <div className="pre">{planText}</div>
        ) : (
          <div className="muted">Henüz plan üretilmedi.</div>
        )}

        <div className="actions">
          <button className="btn btn-secondary" onClick={onGoToFriends}>
            Canlı Odaya Git
          </button>
          <button className="btn btn-secondary" onClick={onBack}>
            Geri
          </button>
        </div>
      </div>
    </div>
  );
}

export default DashboardPage;
